/**
 * Branch Module Service Tests
 *
 * Unit tests for BranchService covering:
 * - Branch CRUD operations with tenant isolation
 * - Settings management
 * - Status changes
 * - Hierarchy management (parent/child relationships)
 * - Code validation
 *
 * @module modules/_core/branch/__tests__/branch.service.spec
 */

import { describe, it, expect, beforeEach, vi, type Mock } from 'vitest';

import { BranchService } from '@/modules/_core/branch/branch.service';
import { AppException } from '@/core/exceptions/app.exception';
import type { EventService } from '@/core/services/event.service';
import type { BranchStatus } from '@/modules/_core/branch/branch.types';

// -----------------------------------------------------------------------------
// Mock Factories
// -----------------------------------------------------------------------------

/**
 * Creates a mock BranchRepository
 */
function createMockRepository() {
  return {
    findAll: vi.fn(),
    findAllSummaries: vi.fn(),
    findById: vi.fn(),
    findByIdWithRelations: vi.fn(),
    findByIdOrThrow: vi.fn(),
    findByCode: vi.fn(),
    findMainBranch: vi.fn(),
    findRootBranches: vi.fn(),
    findChildren: vi.fn(),
    codeExists: vi.fn(),
    count: vi.fn(),
    getHierarchyDepth: vi.fn(),
    create: vi.fn(),
    update: vi.fn(),
    updateSettings: vi.fn(),
    updateStatus: vi.fn(),
    setAsMain: vi.fn(),
    softDelete: vi.fn(),
    restore: vi.fn(),
  };
}

/**
 * Creates a mock EventService
 */
function createMockEventService(): { emitCustom: Mock } {
  return {
    emitCustom: vi.fn(),
  };
}

/**
 * Creates a mock branch for testing
 */
function createMockBranch(overrides: Partial<{
  id: string;
  organizationId: string;
  name: string;
  code: string;
  description: string | null;
  phone: string | null;
  email: string | null;
  address: Record<string, unknown> | null;
  settings: Record<string, unknown>;
  status: BranchStatus;
  parentId: string | null;
  sortOrder: number;
  isMain: boolean;
  createdAt: Date;
  updatedAt: Date;
  deletedAt: Date | null;
}> = {}) {
  return {
    id: 'branch_123',
    organizationId: 'org_123',
    name: 'Main Branch',
    code: 'MAIN',
    description: 'Main branch location',
    phone: '+905551234567',
    email: 'main@branch.com',
    address: { city: 'Istanbul', district: 'Kadikoy' },
    settings: { openingTime: '09:00', closingTime: '22:00' },
    status: 'ACTIVE' as BranchStatus,
    parentId: null,
    sortOrder: 0,
    isMain: true,
    createdAt: new Date(),
    updatedAt: new Date(),
    deletedAt: null,
    ...overrides,
  };
}

/**
 * Creates a mock branch with relations for testing
 */
function createMockBranchWithRelations(overrides: Partial<ReturnType<typeof createMockBranch>> = {}) {
  return {
    ...createMockBranch(overrides),
    parent: null,
    children: [],
    organization: {
      id: 'org_123',
      name: 'Test Organization',
      slug: 'test-org',
    },
    _count: {
      children: 0,
      menus: 2,
      tables: 10,
      orders: 150,
    },
  };
}

// -----------------------------------------------------------------------------
// Test Suite
// -----------------------------------------------------------------------------

describe('BranchService', () => {
  let service: BranchService;
  let mockRepository: ReturnType<typeof createMockRepository>;
  let mockEventService: ReturnType<typeof createMockEventService>;

  beforeEach(() => {
    mockRepository = createMockRepository();
    mockEventService = createMockEventService();

    service = new BranchService(
      mockRepository as unknown as Parameters<typeof BranchService['prototype']['constructor']>[0],
      mockEventService as unknown as EventService
    );
  });

  // ---------------------------------------------------------------------------
  // List Operations Tests
  // ---------------------------------------------------------------------------

  describe('list', () => {
    it('should return paginated branches for organization', async () => {
      // Arrange
      const mockBranches = [createMockBranch(), createMockBranch({ id: 'branch_456' })];
      mockRepository.findAll.mockResolvedValue({
        data: mockBranches,
        meta: { page: 1, perPage: 20, total: 2, totalPages: 1 },
      });

      // Act
      const result = await service.list('org_123', { page: 1, perPage: 20 });

      // Assert
      expect(result.data).toHaveLength(2);
      expect(result.meta.total).toBe(2);
      expect(mockRepository.findAll).toHaveBeenCalledWith(
        'org_123',
        expect.objectContaining({ page: 1, perPage: 20 })
      );
    });

    it('should apply status filter', async () => {
      // Arrange
      mockRepository.findAll.mockResolvedValue({
        data: [],
        meta: { page: 1, perPage: 20, total: 0, totalPages: 0 },
      });

      // Act
      await service.list('org_123', { status: 'ACTIVE' as BranchStatus });

      // Assert
      expect(mockRepository.findAll).toHaveBeenCalledWith(
        'org_123',
        expect.objectContaining({ status: 'ACTIVE' })
      );
    });
  });

  describe('listSummaries', () => {
    it('should return branch summaries', async () => {
      // Arrange
      const mockSummaries = [
        { id: 'branch_1', name: 'Branch 1', code: 'BR1' },
        { id: 'branch_2', name: 'Branch 2', code: 'BR2' },
      ];
      mockRepository.findAllSummaries.mockResolvedValue(mockSummaries);

      // Act
      const result = await service.listSummaries('org_123');

      // Assert
      expect(result).toHaveLength(2);
      expect(mockRepository.findAllSummaries).toHaveBeenCalledWith('org_123', undefined);
    });
  });

  // ---------------------------------------------------------------------------
  // Read Operations Tests
  // ---------------------------------------------------------------------------

  describe('getById', () => {
    it('should return branch by ID with tenant isolation', async () => {
      // Arrange
      const mockBranch = createMockBranch();
      mockRepository.findById.mockResolvedValue(mockBranch);

      // Act
      const result = await service.getById('org_123', 'branch_123');

      // Assert
      expect(result).toEqual(mockBranch);
      expect(mockRepository.findById).toHaveBeenCalledWith('branch_123', 'org_123');
    });

    it('should return null when branch not found', async () => {
      // Arrange
      mockRepository.findById.mockResolvedValue(null);

      // Act
      const result = await service.getById('org_123', 'nonexistent');

      // Assert
      expect(result).toBeNull();
    });
  });

  describe('getByIdWithRelations', () => {
    it('should return branch with relations', async () => {
      // Arrange
      const mockBranch = createMockBranchWithRelations();
      mockRepository.findByIdWithRelations.mockResolvedValue(mockBranch);

      // Act
      const result = await service.getByIdWithRelations('org_123', 'branch_123');

      // Assert
      expect(result).toHaveProperty('organization');
      expect(result).toHaveProperty('_count');
    });

    it('should throw error when branch not found', async () => {
      // Arrange
      mockRepository.findByIdWithRelations.mockResolvedValue(null);

      // Act & Assert
      await expect(
        service.getByIdWithRelations('org_123', 'nonexistent')
      ).rejects.toThrow(AppException);
    });
  });

  describe('getByCode', () => {
    it('should return branch by code', async () => {
      // Arrange
      const mockBranch = createMockBranch();
      mockRepository.findByCode.mockResolvedValue(mockBranch);

      // Act
      const result = await service.getByCode('org_123', 'MAIN');

      // Assert
      expect(result).toEqual(mockBranch);
      expect(mockRepository.findByCode).toHaveBeenCalledWith('org_123', 'MAIN');
    });
  });

  describe('getMainBranch', () => {
    it('should return main branch', async () => {
      // Arrange
      const mockBranch = createMockBranch({ isMain: true });
      mockRepository.findMainBranch.mockResolvedValue(mockBranch);

      // Act
      const result = await service.getMainBranch('org_123');

      // Assert
      expect(result?.isMain).toBe(true);
    });

    it('should return null when no main branch', async () => {
      // Arrange
      mockRepository.findMainBranch.mockResolvedValue(null);

      // Act
      const result = await service.getMainBranch('org_123');

      // Assert
      expect(result).toBeNull();
    });
  });

  describe('getSettings', () => {
    it('should return branch settings', async () => {
      // Arrange
      const mockBranch = createMockBranch({
        settings: { openingTime: '09:00', closingTime: '22:00' },
      });
      mockRepository.findByIdOrThrow.mockResolvedValue(mockBranch);

      // Act
      const result = await service.getSettings('org_123', 'branch_123');

      // Assert
      expect(result).toEqual({ openingTime: '09:00', closingTime: '22:00' });
    });
  });

  describe('getHierarchy', () => {
    it('should return children when branch ID provided', async () => {
      // Arrange
      const children = [
        createMockBranch({ id: 'child_1', parentId: 'branch_123' }),
        createMockBranch({ id: 'child_2', parentId: 'branch_123' }),
      ];
      mockRepository.findChildren.mockResolvedValue(children);

      // Act
      const result = await service.getHierarchy('org_123', 'branch_123');

      // Assert
      expect(result).toHaveLength(2);
      expect(mockRepository.findChildren).toHaveBeenCalledWith('org_123', 'branch_123');
    });

    it('should return root branches when no branch ID provided', async () => {
      // Arrange
      const rootBranches = [createMockBranch({ parentId: null })];
      mockRepository.findRootBranches.mockResolvedValue(rootBranches);

      // Act
      const result = await service.getHierarchy('org_123');

      // Assert
      expect(result).toHaveLength(1);
      expect(mockRepository.findRootBranches).toHaveBeenCalledWith('org_123');
    });
  });

  describe('count', () => {
    it('should return branch count for organization', async () => {
      // Arrange
      mockRepository.count.mockResolvedValue(5);

      // Act
      const result = await service.count('org_123');

      // Assert
      expect(result).toBe(5);
      expect(mockRepository.count).toHaveBeenCalledWith('org_123', undefined);
    });
  });

  // ---------------------------------------------------------------------------
  // Create Operations Tests
  // ---------------------------------------------------------------------------

  describe('create', () => {
    const validCreateData = {
      name: 'Downtown Branch',
      description: 'Downtown location',
      phone: '+905559876543',
    };

    it('should create branch successfully', async () => {
      // Arrange
      mockRepository.codeExists.mockResolvedValue(false);
      mockRepository.count.mockResolvedValue(1); // Not first branch
      const createdBranch = createMockBranch({
        id: 'branch_new',
        name: validCreateData.name,
        code: 'DOWNTOWN',
        isMain: false,
      });
      mockRepository.create.mockResolvedValue(createdBranch);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.create('org_123', validCreateData);

      // Assert
      expect(result.branch).toEqual(createdBranch);
      expect(result.message).toContain('successfully');
      expect(mockRepository.create).toHaveBeenCalledWith(
        'org_123',
        expect.objectContaining({
          name: validCreateData.name,
          status: 'ACTIVE',
        })
      );
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'branch.created',
        expect.objectContaining({
          branchId: createdBranch.id,
          organizationId: 'org_123',
        })
      );
    });

    it('should set first branch as main automatically', async () => {
      // Arrange
      mockRepository.codeExists.mockResolvedValue(false);
      mockRepository.count.mockResolvedValue(0); // First branch
      const createdBranch = createMockBranch({ isMain: true });
      mockRepository.create.mockResolvedValue(createdBranch);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.create('org_123', validCreateData);

      // Assert
      expect(mockRepository.create).toHaveBeenCalledWith(
        'org_123',
        expect.objectContaining({ isMain: true })
      );
    });

    it('should auto-generate unique code', async () => {
      // Arrange
      mockRepository.codeExists
        .mockResolvedValueOnce(true)  // First code exists
        .mockResolvedValueOnce(false); // Second code available
      mockRepository.count.mockResolvedValue(1);
      mockRepository.create.mockResolvedValue(createMockBranch({ code: 'DOWNTOWN-1' }));
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.create('org_123', validCreateData);

      // Assert
      expect(mockRepository.codeExists).toHaveBeenCalledTimes(2);
    });

    it('should throw error when custom code already exists', async () => {
      // Arrange
      mockRepository.codeExists.mockResolvedValue(true);

      // Act & Assert
      await expect(
        service.create('org_123', { ...validCreateData, code: 'EXISTING' })
      ).rejects.toThrow(AppException);

      expect(mockRepository.create).not.toHaveBeenCalled();
    });

    it('should validate parent branch exists', async () => {
      // Arrange
      mockRepository.codeExists.mockResolvedValue(false);
      mockRepository.findByIdOrThrow.mockRejectedValue(AppException.notFound('Branch', 'parent_123'));

      // Act & Assert
      await expect(
        service.create('org_123', { ...validCreateData, parentId: 'parent_123' })
      ).rejects.toThrow(AppException);
    });

    it('should enforce hierarchy depth limit', async () => {
      // Arrange
      mockRepository.codeExists.mockResolvedValue(false);
      mockRepository.findByIdOrThrow.mockResolvedValue(createMockBranch());
      mockRepository.getHierarchyDepth.mockResolvedValue(5); // MAX_HIERARCHY_DEPTH

      // Act & Assert
      await expect(
        service.create('org_123', { ...validCreateData, parentId: 'deep_parent' })
      ).rejects.toThrow(AppException);
    });
  });

  // ---------------------------------------------------------------------------
  // Update Operations Tests
  // ---------------------------------------------------------------------------

  describe('update', () => {
    const validUpdateData = {
      name: 'Updated Branch Name',
    };

    it('should update branch successfully', async () => {
      // Arrange
      const currentBranch = createMockBranch();
      const updatedBranch = createMockBranch({ name: validUpdateData.name });
      mockRepository.findByIdOrThrow.mockResolvedValue(currentBranch);
      mockRepository.update.mockResolvedValue(updatedBranch);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.update('org_123', 'branch_123', validUpdateData);

      // Assert
      expect(result.branch.name).toBe(validUpdateData.name);
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'branch.updated',
        expect.objectContaining({
          branchId: 'branch_123',
          organizationId: 'org_123',
        })
      );
    });

    it('should check code uniqueness when updating code', async () => {
      // Arrange
      const currentBranch = createMockBranch({ code: 'OLD' });
      mockRepository.findByIdOrThrow.mockResolvedValue(currentBranch);
      mockRepository.codeExists.mockResolvedValue(true);

      // Act & Assert
      await expect(
        service.update('org_123', 'branch_123', { code: 'EXISTING' })
      ).rejects.toThrow(AppException);
    });

    it('should prevent setting self as parent', async () => {
      // Arrange
      const currentBranch = createMockBranch();
      mockRepository.findByIdOrThrow.mockResolvedValue(currentBranch);

      // Act & Assert
      await expect(
        service.update('org_123', 'branch_123', { parentId: 'branch_123' })
      ).rejects.toThrow(AppException);
    });

    it('should prevent circular hierarchy', async () => {
      // Arrange
      const currentBranch = createMockBranch({ id: 'branch_123' });
      const childBranch = createMockBranch({ id: 'child_branch', parentId: 'branch_123' });
      mockRepository.findByIdOrThrow
        .mockResolvedValueOnce(currentBranch)  // Current branch
        .mockResolvedValueOnce(childBranch);   // Potential new parent (which is a child)
      mockRepository.getHierarchyDepth.mockResolvedValue(1);
      // Simulate circular reference detection
      mockRepository.findById
        .mockResolvedValueOnce(childBranch)
        .mockResolvedValueOnce(currentBranch); // Would create circle

      // Act & Assert
      await expect(
        service.update('org_123', 'branch_123', { parentId: 'child_branch' })
      ).rejects.toThrow(AppException);
    });
  });

  describe('updateSettings', () => {
    it('should update settings successfully', async () => {
      // Arrange
      const currentBranch = createMockBranch({ settings: { openingTime: '09:00' } });
      const updatedBranch = createMockBranch({
        settings: { openingTime: '09:00', closingTime: '23:00' },
      });
      mockRepository.findByIdOrThrow.mockResolvedValue(currentBranch);
      mockRepository.updateSettings.mockResolvedValue(updatedBranch);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.updateSettings('org_123', 'branch_123', {
        settings: { closingTime: '23:00' },
      });

      // Assert
      expect(result.settings).toEqual({ openingTime: '09:00', closingTime: '23:00' });
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'branch.settings.updated',
        expect.any(Object)
      );
    });
  });

  describe('changeStatus', () => {
    it('should change status successfully', async () => {
      // Arrange
      const currentBranch = createMockBranch({ status: 'ACTIVE' as BranchStatus });
      const updatedBranch = createMockBranch({ status: 'INACTIVE' as BranchStatus });
      mockRepository.findByIdOrThrow.mockResolvedValue(currentBranch);
      mockRepository.updateStatus.mockResolvedValue(updatedBranch);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.changeStatus('org_123', 'branch_123', {
        status: 'INACTIVE' as BranchStatus,
        reason: 'Temporary closure',
      });

      // Assert
      expect(result.branch.status).toBe('INACTIVE');
      expect(result.previousStatus).toBe('ACTIVE');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'branch.status.changed',
        expect.objectContaining({
          previousStatus: 'ACTIVE',
          newStatus: 'INACTIVE',
        })
      );
    });

    it('should return unchanged when status is same', async () => {
      // Arrange
      const currentBranch = createMockBranch({ status: 'ACTIVE' as BranchStatus });
      mockRepository.findByIdOrThrow.mockResolvedValue(currentBranch);

      // Act
      const result = await service.changeStatus('org_123', 'branch_123', {
        status: 'ACTIVE' as BranchStatus,
      });

      // Assert
      expect(result.message).toContain('unchanged');
      expect(mockRepository.updateStatus).not.toHaveBeenCalled();
    });
  });

  describe('setAsMain', () => {
    it('should set branch as main successfully', async () => {
      // Arrange
      const updatedBranch = createMockBranch({ isMain: true });
      mockRepository.setAsMain.mockResolvedValue(updatedBranch);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.setAsMain('org_123', 'branch_123');

      // Assert
      expect(result.isMain).toBe(true);
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'branch.updated',
        expect.objectContaining({
          changes: { isMain: true },
        })
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Delete Operations Tests
  // ---------------------------------------------------------------------------

  describe('delete', () => {
    it('should soft delete branch successfully', async () => {
      // Arrange
      const mockBranch = createMockBranch({ isMain: false });
      mockRepository.findByIdOrThrow.mockResolvedValue(mockBranch);
      mockRepository.findChildren.mockResolvedValue([]);
      mockRepository.softDelete.mockResolvedValue(undefined);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.delete('org_123', 'branch_123');

      // Assert
      expect(mockRepository.softDelete).toHaveBeenCalledWith('branch_123', 'org_123');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'branch.deleted',
        expect.objectContaining({
          branchId: 'branch_123',
          organizationId: 'org_123',
        })
      );
    });

    it('should throw error when branch has children', async () => {
      // Arrange
      const mockBranch = createMockBranch();
      mockRepository.findByIdOrThrow.mockResolvedValue(mockBranch);
      mockRepository.findChildren.mockResolvedValue([
        createMockBranch({ id: 'child_1' }),
      ]);

      // Act & Assert
      await expect(
        service.delete('org_123', 'branch_123')
      ).rejects.toThrow(AppException);

      expect(mockRepository.softDelete).not.toHaveBeenCalled();
    });

    it('should throw error when deleting main branch', async () => {
      // Arrange
      const mockBranch = createMockBranch({ isMain: true });
      mockRepository.findByIdOrThrow.mockResolvedValue(mockBranch);
      mockRepository.findChildren.mockResolvedValue([]);

      // Act & Assert
      await expect(
        service.delete('org_123', 'branch_123')
      ).rejects.toThrow(AppException);

      expect(mockRepository.softDelete).not.toHaveBeenCalled();
    });
  });

  describe('restore', () => {
    it('should restore branch successfully', async () => {
      // Arrange
      const restoredBranch = createMockBranch();
      mockRepository.restore.mockResolvedValue(restoredBranch);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.restore('org_123', 'branch_123');

      // Assert
      expect(result).toEqual(restoredBranch);
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'branch.restored',
        expect.any(Object)
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Validation Operations Tests
  // ---------------------------------------------------------------------------

  describe('isCodeAvailable', () => {
    it('should return true when code is available', async () => {
      // Arrange
      mockRepository.codeExists.mockResolvedValue(false);

      // Act
      const result = await service.isCodeAvailable('org_123', 'NEW-CODE');

      // Assert
      expect(result).toBe(true);
    });

    it('should return false when code exists', async () => {
      // Arrange
      mockRepository.codeExists.mockResolvedValue(true);

      // Act
      const result = await service.isCodeAvailable('org_123', 'EXISTING');

      // Assert
      expect(result).toBe(false);
    });

    it('should exclude specific ID when checking', async () => {
      // Arrange
      mockRepository.codeExists.mockResolvedValue(false);

      // Act
      await service.isCodeAvailable('org_123', 'CODE', 'branch_123');

      // Assert
      expect(mockRepository.codeExists).toHaveBeenCalledWith('org_123', 'CODE', 'branch_123');
    });
  });
});
